USE population_miniterm;

SELECT 'active_residence_per_person' check_name,COUNT(*) abnormal_count FROM (SELECT person_id FROM residence WHERE status='ACTIVE' GROUP BY person_id HAVING COUNT(*)>1) x
UNION ALL SELECT 'active_membership_per_person',COUNT(*) FROM (SELECT person_id FROM household_member WHERE status='ACTIVE' GROUP BY person_id HAVING COUNT(*)>1) x
UNION ALL SELECT 'household_head_missing',COUNT(*) FROM household h LEFT JOIN person p ON p.person_id=h.head_person_id WHERE h.household_no LIKE 'DEMO-HH2-%' AND p.person_id IS NULL
UNION ALL SELECT 'head_not_active_member',COUNT(*) FROM household h LEFT JOIN household_member hm ON hm.household_id=h.household_id AND hm.person_id=h.head_person_id AND hm.relationship='HEAD' AND hm.status='ACTIVE' WHERE h.household_no LIKE 'DEMO-HH2-%' AND hm.member_id IS NULL
UNION ALL SELECT 'head_relation_mismatch',COUNT(*) FROM household_member hm JOIN household h ON h.household_id=hm.household_id WHERE h.household_no LIKE 'DEMO-HH2-%' AND hm.relationship='HEAD' AND hm.status='ACTIVE' AND hm.person_id<>h.head_person_id
UNION ALL SELECT 'completed_out_has_active_residence',COUNT(*) FROM migration_out mo JOIN person p ON p.person_id=mo.person_id JOIN residence r ON r.person_id=p.person_id AND r.status='ACTIVE' WHERE mo.business_status='COMPLETED' AND p.id_card IN('110101198001010010','110101198202020020','110101201203030030','110105197504040044','110105199505050059','110105199606060061','110106198707070076','110106199808080083','110102199909090090')
UNION ALL SELECT 'completed_out_has_active_member',COUNT(*) FROM migration_out mo JOIN person p ON p.person_id=mo.person_id JOIN household_member hm ON hm.person_id=p.person_id AND hm.status='ACTIVE' WHERE mo.business_status='COMPLETED' AND p.id_card LIKE '110%'
UNION ALL SELECT 'archive_orphan_person',COUNT(*) FROM residence_archive ra LEFT JOIN person p ON p.person_id=ra.person_id WHERE ra.archive_id IS NOT NULL AND p.person_id IS NULL
UNION ALL SELECT 'archive_orphan_household',COUNT(*) FROM residence_archive ra LEFT JOIN household h ON h.household_id=ra.household_id WHERE ra.archive_id IS NOT NULL AND h.household_id IS NULL
UNION ALL SELECT 'migration_in_duplicate_application',COUNT(*) FROM (SELECT application_id FROM migration_in WHERE application_id IS NOT NULL GROUP BY application_id HAVING COUNT(*)>1) x
UNION ALL SELECT 'migration_out_duplicate_application',COUNT(*) FROM (SELECT application_id FROM migration_out WHERE application_id IS NOT NULL GROUP BY application_id HAVING COUNT(*)>1) x
UNION ALL SELECT 'demo_duplicate_identity',COUNT(*) FROM (SELECT id_card FROM person WHERE id_card IN('110101198001010010','110101198202020020','110101201203030030','110105197504040044','110105199505050059','110105199606060061','110106198707070076','110106199808080083','110102199909090090') GROUP BY id_card HAVING COUNT(*)>1) x
UNION ALL SELECT 'demo_invalid_identity',COUNT(*) FROM person p WHERE p.id_card IN('110101198001010010','110101198202020020','110101201203030030','110105197504040044','110105199505050059','110105199606060061','110106198707070076','110106199808080083','110102199909090090') AND (p.id_card NOT REGEXP '^[0-9]{17}[0-9X]$' OR STR_TO_DATE(SUBSTRING(p.id_card,7,8),'%Y%m%d') IS NULL OR SUBSTRING('10X98765432',MOD(CAST(SUBSTRING(p.id_card,1,1) AS UNSIGNED)*7+CAST(SUBSTRING(p.id_card,2,1) AS UNSIGNED)*9+CAST(SUBSTRING(p.id_card,3,1) AS UNSIGNED)*10+CAST(SUBSTRING(p.id_card,4,1) AS UNSIGNED)*5+CAST(SUBSTRING(p.id_card,5,1) AS UNSIGNED)*8+CAST(SUBSTRING(p.id_card,6,1) AS UNSIGNED)*4+CAST(SUBSTRING(p.id_card,7,1) AS UNSIGNED)*2+CAST(SUBSTRING(p.id_card,8,1) AS UNSIGNED)+CAST(SUBSTRING(p.id_card,9,1) AS UNSIGNED)*6+CAST(SUBSTRING(p.id_card,10,1) AS UNSIGNED)*3+CAST(SUBSTRING(p.id_card,11,1) AS UNSIGNED)*7+CAST(SUBSTRING(p.id_card,12,1) AS UNSIGNED)*9+CAST(SUBSTRING(p.id_card,13,1) AS UNSIGNED)*10+CAST(SUBSTRING(p.id_card,14,1) AS UNSIGNED)*5+CAST(SUBSTRING(p.id_card,15,1) AS UNSIGNED)*8+CAST(SUBSTRING(p.id_card,16,1) AS UNSIGNED)*4+CAST(SUBSTRING(p.id_card,17,1) AS UNSIGNED)*2,11)+1,1)<>UPPER(RIGHT(p.id_card,1)))
UNION ALL SELECT 'demo_member_orphan',COUNT(*) FROM household_member hm LEFT JOIN person p ON p.person_id=hm.person_id LEFT JOIN household h ON h.household_id=hm.household_id WHERE (p.person_id IS NULL OR h.household_id IS NULL)
UNION ALL SELECT 'demo_residence_orphan',COUNT(*) FROM residence r LEFT JOIN person p ON p.person_id=r.person_id LEFT JOIN household h ON h.household_id=r.household_id WHERE (p.person_id IS NULL OR h.household_id IS NULL)
UNION ALL SELECT 'required_demo_account_missing',5-COUNT(*) FROM sys_user WHERE username IN('viewer','population','household','approver','admin')
UNION ALL SELECT 'fake_minio_material',COUNT(*) FROM application_material WHERE storage_path LIKE 'minio://%'
UNION ALL SELECT 'inbound_candidate_has_residence',COUNT(*) FROM residence r JOIN person p ON p.person_id=r.person_id WHERE p.id_card='110106199808080083' AND r.status='ACTIVE';
